    VendTable                       vendTable;
    InventTable                     inventTable;
    ProjTable						projTable;
    Common                          callerTable;

    FWFTextBlockModule              module;
    FWFTextBlockProductType         productType;
    FWFTextBlockAccountRelationType accountType;

    TableGroupAll                   accountCode;
    TableGroupAll                   itemCode;
    FWFTextBlockAccountRelation     accountRelation;
    ItemRelation                    itemRelation;

    boolean                         isRelation;
    boolean                         initializing;
    QueryBuildRange                 blockCode;
    QueryBuildRange                 blockCodeOrderedItems;

