private str buildInventCustVendFilter()
{
    str						filter;
    FWFTextBlockGroupAssign groupAssign;

    void addTableFilter(str _fieldStrCode, int _code, str _fieldStrRel, str _rel)
    {
        filter = '(' + this.relationFilter(_fieldStrCode, _code, _fieldStrRel, _rel) + ' || ' + this.relationCodeAllFilter(_fieldStrCode) + ')';
    }

    void addGroupFilter(str _fieldStrCode, str _fieldStrRel, str _rel)
    {
        if (_rel)
        {
            filter += ' || ' + this.relationFilter(_fieldStrCode, any2int(TableGroupAll::GroupId), _fieldStrRel, _rel);
        }
    }

    switch(callerTable.TableId)
    {
        case tableNum(InventTable) :
            addTableFilter(fieldStr(FWFTextBlockUsage, ItemCode), any2int(itemCode), fieldStr(FWFTextBlockUsage, ItemRelation), itemRelation);
            while select groupAssign where groupAssign.RefId == inventTable.ItemId
            {
                addGroupFilter(fieldStr(FWFTextBlockUsage, ItemCode), fieldStr(FWFTextBlockUsage, ItemRelation), groupAssign.GroupId);
            }
            break;

        case tableNum(VendTable) :
            addTableFilter(fieldStr(FWFTextBlockUsage, AccountCode), any2int(accountCode), fieldStr(FWFTextBlockUsage, AccountRelation), accountRelation);
            while select groupAssign where groupAssign.RefId == vendTable.AccountNum
            {
                addGroupFilter(fieldStr(FWFTextBlockUsage, AccountCode), fieldStr(FWFTextBlockUsage, AccountRelation), groupAssign.GroupId);
            }
            break;

        case tableNum(CustTable) :
            addTableFilter(fieldStr(FWFTextBlockUsage, AccountCode), any2int(accountCode), fieldStr(FWFTextBlockUsage, AccountRelation), accountRelation);
            while select groupAssign where groupAssign.RefId == custTable.AccountNum
            {
                addGroupFilter(fieldStr(FWFTextBlockUsage, AccountCode), fieldStr(FWFTextBlockUsage, AccountRelation), groupAssign.GroupId);
            }
            break;

        case tableNum(ProjTable) :
            addTableFilter(fieldStr(FWFTextBlockUsage, AccountCode), any2int(accountCode), fieldStr(FWFTextBlockUsage, AccountRelation), accountRelation);
            while select groupAssign where groupAssign.RefId == projTable.ProjId
            {
                addGroupFilter(fieldStr(FWFTextBlockUsage, AccountCode), fieldStr(FWFTextBlockUsage, AccountRelation), groupAssign.GroupId);
            }
            break;
    }

    return filter ? '(' + filter + ')' : '';
}

public void clearInventDim()
{
    FWFTextBlockUsage.InventDimId = InventDim::inventDimIdBlank();
    inventDim.data(InventDim::find(FWFTextBlockUsage.InventDimId));
    inventDim_ds.setCurrent();
    inventDim_ds.refresh();
}

void enableRelationFields()
{
    if (FWFTextBlockUsage.AccountType == FWFTextBlockAccountRelationType::Prod)
    {
        FWFTextBlockUsage_ds.object(fieldNum(FWFTextBlockUsage, AccountCode)).skip(true);
        FWFTextBlockUsage_ds.object(fieldNum(FWFTextBlockUsage, AccountCode)).allowEdit(false);
    }
    else
    {
        FWFTextBlockUsage_ds.object(fieldNum(FWFTextBlockUsage, AccountCode)).skip(false);
        FWFTextBlockUsage_ds.object(fieldNum(FWFTextBlockUsage, AccountCode)).allowEdit(true);
    }

    if (FWFTextBlockUsage.ItemCode == TableGroupAll::All)
    {
        FWFTextBlockUsage_ds.object(fieldNum(FWFTextBlockUsage, ItemRelation)).skip(true);
        FWFTextBlockUsage_ds.object(fieldNum(FWFTextBlockUsage, ItemRelation)).allowEdit(false);
    }
    else
    {
        FWFTextBlockUsage_ds.object(fieldNum(FWFTextBlockUsage, ItemRelation)).skip(false);
        FWFTextBlockUsage_ds.object(fieldNum(FWFTextBlockUsage, ItemRelation)).allowEdit(true);
    }

    if (FWFTextBlockUsage.AccountCode == TableGroupAll::All)
    {
        FWFTextBlockUsage_ds.object(fieldNum(FWFTextBlockUsage, AccountRelation)).skip(true);
        FWFTextBlockUsage_ds.object(fieldNum(FWFTextBlockUsage, AccountRelation)).allowEdit(false);
    }
    else
    {
        FWFTextBlockUsage_ds.object(fieldNum(FWFTextBlockUsage, AccountRelation)).skip(false);
        FWFTextBlockUsage_ds.object(fieldNum(FWFTextBlockUsage, AccountRelation)).allowEdit(true);
    }
}

public void  init()
{
    initializing = true;

    super();

    element.initParameters();

    element.updateDesign(InventDimFormDesignUpdate::Init);

    initializing = false;
}

    void  initParameters()
    {

        FWFTextBlockUsage_ds.query().dataSourceTable(tableNum(FWFTextBlockUsage)).clearRanges();
        FWFTextBlockUsage_ds.query().dataSourceTable(tableNum(FWFTextBlockUsage)).clearDynalinks();

        if (element.args().record())
        {
            isRelation = true;
        }
        if (element.args().parmEnumType() == enumNum(FWFTextBlockModule))
        {
            module = element.args().parmEnum();
        }
        else
        {
            throw error(error::wrongUseOfFunction(funcName()));
        }

        if (element.args() && element.args().record())
        {
            callerTable = element.args().record();
        }

        accountCode = TableGroupAll::All;
        itemCode    = TableGroupAll::All;

        switch(callerTable.TableId)
        {
            case tableNum(CustTable) :
                custTable       = element.args().record();
                accountCode     = TableGroupAll::Table;
                accountRelation = custTable.AccountNum;
                break;

            case tableNum(VendTable) :
                vendTable       = element.args().record();
                accountCode     = TableGroupAll::Table;
                accountRelation = vendTable.AccountNum;
                break;

            case tableNum(InventTable)  :
                inventTable     = element.args().record();
                if (module == FWFTextBlockModule::ReleasedProduct)
                {
                    itemCode     = TableGroupAll::Table;
                    itemRelation = inventTable.ItemId;
                }
                break;

            case tableNum(ProjTable) :
                projTable       = element.args().record();
                accountCode     = TableGroupAll::Table;
                accountRelation = projTable.ProjId;
                break;
        }

        FWFTextBlockUsage_ds.object(fieldNum(FWFTextBlockUsage, AccountType)).visible(false);
        FWFTextBlockUsage_ds.object(fieldNum(FWFTextBlockUsage, ItemCode)).visible(false);
        FWFTextBlockUsage_ds.object(fieldNum(FWFTextBlockUsage, ItemRelation)).visible(false);
        ItemName.visible(false);

        switch (module)
        {
            case FWFTextBlockModule::Customer:
                custVendName.label("@SYS24704");
                FWFTextBlockUsage_AccountRelation.label(CustVendName.label());
                accountType  = FWFTextBlockAccountRelationType::Cust;
                productType  = FWFTextBlockProductType::None;
                FWFTextBlockUsage_ds.query().dataSourceTable(tableNum(FWFTextBlockUsage)).addRange(fieldNum(FWFTextBlockUsage, AccountType)).value(queryValue(accountType));
                break;

            case FWFTextBlockModule::Supplier:
                custVendName.label("@SYS9455");
                FWFTextBlockUsage_AccountRelation.label(CustVendName.label());
                accountType     = FWFTextBlockAccountRelationType::Vend;
                productType     = FWFTextBlockProductType::None;
                FWFTextBlockUsage_ds.query().dataSourceTable(tableNum(FWFTextBlockUsage)).addRange(fieldNum(FWFTextBlockUsage, AccountType)).value(queryValue(accountType));
                break;

            case FWFTextBlockModule::ReleasedProduct :
                custVendName.label("@SYS22898");
                FWFTextBlockUsage_AccountRelation.label(CustVendName.label());
                ItemName.visible(true);
                FWFTextBlockUsage_ds.object(fieldNum(FWFTextBlockUsage, AccountType)).visible(true);
                FWFTextBlockUsage_ds.object(fieldNum(FWFTextBlockUsage, ItemCode)).visible(true);
                FWFTextBlockUsage_ds.object(fieldNum(FWFTextBlockUsage, ItemRelation)).visible(true);
                productType  = FWFTextBlockProductType::ReleasedProduct;

                if (element.args().parm() == 'Vend')
                {
                    accountType = FWFTextBlockAccountRelationType::Vend;
                    FWFTextBlockUsage_ds.query().dataSourceTable(tableNum(FWFTextBlockUsage)).addRange(fieldNum(FWFTextBlockUsage, AccountType)).value(queryValue(accountType));
                }
                else if (element.args().parm() == 'Cust')
                {
                    accountType = FWFTextBlockAccountRelationType::Cust;
                    FWFTextBlockUsage_ds.query().dataSourceTable(tableNum(FWFTextBlockUsage)).addRange(fieldNum(FWFTextBlockUsage, AccountType)).value(queryValue(accountType));
                }
				else if (element.args().parm() == 'Proj')
                {
                    accountType = FWFTextBlockAccountRelationType::Proj;
                    FWFTextBlockUsage_ds.query().dataSourceTable(tableNum(FWFTextBlockUsage)).addRange(fieldNum(FWFTextBlockUsage, AccountType)).value(queryValue(accountType));
                }
                break;

            case FWFTextBlockModule::Project :
                custVendName.label("@SYS117835");
                FWFTextBlockUsage_AccountRelation.label(CustVendName.label());
                accountType     = FWFTextBlockAccountRelationType::Proj;
                productType     = FWFTextBlockProductType::None;
                FWFTextBlockUsage_ds.query().dataSourceTable(tableNum(FWFTextBlockUsage)).addRange(fieldNum(FWFTextBlockUsage, AccountType)).value(queryValue(accountType));
                break;

        }

        FWFTextBlockUsage_ds.query().dataSourceTable(tableNum(FWFTextBlockUsage)).addRange(fieldNum(FWFTextBlockUsage, ProductType)).value(queryValue(productType));

        switch (callerTable.TableId)
        {
            case tableNum(InventTable) :
                blockCode = FWFTextBlockUsage_ds.query().dataSourceTable(tableNum(FWFTextBlockUsage)).addRange(fieldNum(FWFTextBlockUsage, ItemCode));
                blockCode.status(RangeStatus::Locked);
                break;

            default :
                blockCode = FWFTextBlockUsage_ds.query().dataSourceTable(tableNum(FWFTextBlockUsage)).addRange(fieldNum(FWFTextBlockUsage, AccountCode));
                blockCode.status(RangeStatus::Locked);
                break;
        }

    }

