str relationCodeAllFilter(str _fieldStrCode)
{
    str     dsName      = FWFTextBlockUsage_ds.queryRun().query().dataSourceTable(tableNum(FWFTextBlockUsage)).name();
    return strFmt('(%1.%2==%3)', dsName, _fieldStrCode, any2int(TableGroupAll::All));
}

str relationFilter(str _fieldStrCode, int _code, str _fieldStrRel, str _rel)
{
    str     dsName      = FWFTextBlockUsage_ds.queryRun().query().dataSourceTable(tableNum(FWFTextBlockUsage)).name();
    return strFmt('((%1.%2==%3) && (%1.%4=="%5"))', dsName, _fieldStrCode, _code, _fieldStrRel, _rel ? queryValue(_rel) : '');
}

void  reSelect()
{
    str filter;

    if (isRelation)
    {
        filter = this.buildInventCustVendFilter();
    }

    blockCode.value(filter);

    FWFTextBlockUsage_ds.executeQuery();
    FWFTextBlockUsage_ds.queryRun().saveUserSetup(false);
    FWFTextBlockUsage_ds.refresh();
}

void showSalesPurchFields()
{

    switch (FWFTextBlockUsage.AccountType)
    {
        case FWFTextBlockAccountRelationType::Cust:
            if (module != FWFTextBlockModule::Supplier)
            {
                PrintOnPurchFormletters.visible(true);
                PrintOnSalesFormletters.visible(true);
                PrintOnProductionReports.visible(false);
                PrintOnProjectReports.visible(false);
            }
            if (module == FWFTextBlockModule::ReleasedProduct)
            {
                PrintOnPurchFormletters.visible(true);
                PrintOnSalesFormletters.visible(true);
                PrintOnProductionReports.visible(true);
                PrintOnProjectReports.visible(false);
            }
            break;

        case FWFTextBlockAccountRelationType::Vend:
            if (module != FWFTextBlockModule::Customer)
            {
                PrintOnPurchFormletters.visible(true);
                PrintOnSalesFormletters.visible(false);
                PrintOnProductionReports.visible(false);
                PrintOnProjectReports.visible(false);
            }
            break;


        case FWFTextBlockAccountRelationType::Proj:
            PrintOnPurchFormletters.visible(false);
            PrintOnSalesFormletters.visible(true);
            PrintOnProductionReports.visible(false);
            RelatedOrders.visible(false);
            PrintOnProjectReports.visible(true);
            break;

        case FWFTextBlockAccountRelationType::Prod:
            PrintOnPurchFormletters.visible(true);
            PrintOnSalesFormletters.visible(false);
            PrintOnProductionReports.visible(true);
            PrintOnProjectReports.visible(false);
            break;

        default:
            PrintOnPurchFormletters.visible(true);
            PrintOnSalesFormletters.visible(true);
            PrintOnProductionReports.visible(true);
            PrintOnProjectReports.visible(true);
            break;
    }

}

void updateDesign(InventDimFormDesignUpdate mode)
{
    InventDimParm       inventDimParmVisible;
    InventDimParm       inventDimParmEnabled;
    InventDimParm       inventDimParmLocked;

    InventDimGroupSetup inventDimGroupSetup;

    inventTable         localInventTable = inventTable::find(FWFTextBlockUsage.ItemRelation);

    this.showSalesPurchFields();

    switch (mode)
    {
        case InventDimFormDesignUpdate::Init          :
        case InventDimFormDesignUpdate::LinkActive    :
            if (!inventDimFormSetup)
            {
                inventDimFormSetup  = InventDimCtrl::newFromForm(element);
            }
            inventDimFormSetup.parmSkipOnHandLookUp(true);

        case InventDimFormDesignUpdate::Active        :
        case InventDimFormDesignUpdate::FieldChange   :
            inventDimFormSetup.formActiveSetup();
            if (FWFTextBlockUsage.ItemCode == TableGroupAll::Table && FWFTextBlockUsage.ItemRelation)
            {
                //Diviating from the common pattern using InventDimGroupSetup::newItemId(....) to allow the form to load with incomplete dimension settings on the product.
                inventDimGroupSetup = InventDimGroupSetup::newDimensionGroups(localInventTable.productDimensionGroup(), 0, 0);
                inventDimGroupSetup.inventDimParmActive(inventDimParmEnabled);
            }
            else
            {
                inventDimParmEnabled.clear();
            }

            inventDimParmLocked.initNonProductDimAllGroups();

            inventDimParmLocked.InventSiteIdFlag = NoYes::No;
            inventDimParmEnabled.InventSiteIdFlag = NoYes::Yes;
            inventDimParmLocked.InventOwnerIdFlag_RU = NoYes::Yes;

            inventDimFormSetup.parmDimParmLockedRightClick(inventDimParmLocked);
            inventDimFormSetup.parmDimParmVisibleGrid(inventDimParmVisible);
            inventDimFormSetup.parmDimParmEnabled(inventDimParmEnabled);
            inventDimFormSetup.formSetControls(true);

            PrintOnPurchFormletters.enabled(!FWFTextBlockUsage.SetupGroupId);
            PrintOnSalesFormletters.enabled(!FWFTextBlockUsage.SetupGroupId);
            PrintOnProductionReports.enabled(!FWFTextBlockUsage.SetupGroupId);
            PrintOnProjectReports.enabled(!FWFTextBlockUsage.SetupGroupId);
            RelatedOrders.enabled(!FWFTextBlockUsage.SetupGroupId);
            DisplayOptions.enabled(!FWFTextBlockUsage.SetupGroupId);
            FWFTextBlockSetupParm_ds.object(fieldNum(FWFTextBlockSetupParm, Position)).enabled(!FWFTextBlockUsage.SetupGroupId);

            if (HTML)
            {
                HTML.parmHtml(FWFTextBlockLanguage.htmlText());
            }
            break;

        default :
            throw error(strFmt("@SYS54195",funcName()));
    }
}

