// This is itentionally left locally on the form because a migration causes too many RPC calls as call backs are needed to retreive the InventDim record
//BP Deviation documented
display ItemNameDisplay itemName()
{
    Name name;

    switch (FWFTextBlockUsage.ItemCode)
    {
        case  TableGroupAll::Table:
            name = InventTable::find(FWFTextBlockUsage.ItemRelation).itemName(inventDim);
            break;
        case  TableGroupAll::GroupId:
            name = FWFTextBlockGroup::findGroupModule(FWFTextBlockUsage.ItemRelation, FWFTextBlockModule::ReleasedProduct).Description;
            break;
    }

    return name;
}

