public boolean validateWrite()
{
    boolean ret;

    FWFTextBlockUsage.InventDimId = InventDim::findOrCreate(inventDim).InventDimId;

    ret = super();

    return ret;
}

public void write()
{
    FWFTextBlockUsage.InventDimId = InventDim::findOrCreate(inventDim).InventDimId;

    FWFTextBlockUsage.SetupRefRefId = FWFTextBlockSetupParm.RecId;

    super();

    if (FWFTextBlockUsage.InventDimId != inventDim.InventDimId)
    {
        inventDim.data(InventDim::find(FWFTextBlockUsage.InventDimId));
        inventDim_ds.setCurrent();
    }

    FWFTextBlockUsage_ds.reread();
    FWFTextBlockUsage_ds.refresh();
}

void  linkActive()
